class Solution:
    def nodesBetweenCriticalPoints(self, head):
        vals = []
        node = head
        while node:
            vals.append(node.val)
            node = node.next
        n = len(vals)
        crit = []
        for i in range(1, n - 1):
            if (vals[i] > vals[i - 1] and vals[i] > vals[i + 1]) or (vals[i] < vals[i - 1] and vals[i] < vals[i + 1]):
                crit.append(i)
        if len(crit) < 2:
            return [-1, -1]
        min_d = min(crit[k + 1] - crit[k] for k in range(len(crit) - 1))
        max_d = crit[-1] - crit[0]
        return [min_d, max_d]

