class Solution:
    def nodesBetweenCriticalPoints(self, head):
        first = prev_idx = None
        min_dist = None
        prev_val = head.val
        idx = 1
        node = head.next
        while node and node.next:
            is_max = node.val > prev_val and node.val > node.next.val
            is_min = node.val < prev_val and node.val < node.next.val
            if is_max or is_min:
                if first is None:
                    first = idx
                    prev_idx = idx
                else:
                    d = idx - prev_idx
                    if min_dist is None or d < min_dist:
                        min_dist = d
                    prev_idx = idx
            prev_val = node.val
            node = node.next
            idx += 1
        if first is None or first == prev_idx:
            return [-1, -1]
        return [min_dist, prev_idx - first]

