var nodesBetweenCriticalPoints = function(head) {
    let first = null, prevIdx = null, minDist = null;
    let prevVal = head.val;
    let idx = 1;
    let node = head.next;
    while (node && node.next) {
        const isMax = node.val > prevVal && node.val > node.next.val;
        const isMin = node.val < prevVal && node.val < node.next.val;
        if (isMax || isMin) {
            if (first === null) {
                first = idx;
                prevIdx = idx;
            } else {
                const d = idx - prevIdx;
                if (minDist === null || d < minDist) minDist = d;
                prevIdx = idx;
            }
        }
        prevVal = node.val;
        node = node.next;
        idx++;
    }
    if (first === null || first === prevIdx) return [-1, -1];
    return [minDist, prevIdx - first];
};
